queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?role_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:kitchen_role_id ?cg . ?child a :Kitchen_Roles ; p:role_id ?cg . ?l p:restaurant_id ?pg . ?parent a :Restaurants ; p:id ?pg . } GROUP BY ?child }
  ?child p:role_name ?role_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Restaurants } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?role_name WHERE {
  ?restaurants_kitchen_roles a :Restaurants_Kitchen_Roles .
  ?kitchen_roles a :Kitchen_Roles .
  ?restaurants_kitchen_roles p:hasKitchen_Roles ?kitchen_roles .
  ?restaurants a :Restaurants .
  ?restaurants_kitchen_roles p:hasRestaurants ?restaurants .
  ?restaurants p:name ?name .
  ?kitchen_roles p:role_name ?role_name .
} }
  collective: { SELECT ?role_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:kitchen_role_id ?cg . ?child a :Kitchen_Roles ; p:role_id ?cg . ?l p:restaurant_id ?pg . ?parent a :Restaurants ; p:id ?pg . } GROUP BY ?child }
  ?child p:role_name ?role_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Restaurants } }
  FILTER(?nf = ?total)
} }
}
